{
  "type": "QUIZ",
  "lessonText": "Test your understanding of Ancient and Colonial Burma with this quiz.",
  "data": {
    "questions": [
      {
        "question": "What was the significance of Bagan in Ancient Burma?",
        "options": [
          "A center of trade only",
          "A pivotal center of culture and power",
          "A military stronghold",
          "An agricultural hub"
        ],
        "correctAnswer": 1,
        "explanation": "Bagan was a pivotal center of culture and power, influencing the development of Ancient Burma."
      },
      {
        "question": "How did British Colonial Rule impact traditional structures in Burma?",
        "options": [
          "It preserved all traditional practices",
          "It led to the decline of traditional governance",
          "It strengthened local leadership",
          "It had no impact"
        ],
        "correctAnswer": 1,
        "explanation": "British Colonial Rule significantly altered traditional structures, leading to the decline of traditional governance."
      },
      {
        "question": "Which architectural marvel is associated with Bagan?",
        "options": [
          "Shwedagon Pagoda",
          "Ananda Temple",
          "Mandalay Palace",
          "Kyaiktiyo Pagoda"
        ],
        "correctAnswer": 1,
        "explanation": "Ananda Temple is one of the notable architectural marvels associated with Bagan."
      },
      {
        "question": "What role did Bagan play in the spread of Buddhism in Ancient Burma?",
        "options": [
          "It had no role",
          "It was a major center for Buddhist learning",
          "It opposed Buddhism",
          "It was only a trade center"
        ],
        "correctAnswer": 1,
        "explanation": "Bagan was a major center for Buddhist learning, influencing the spread of Buddhism in Ancient Burma."
      }
    ]
  }
}
